    NO MINVALUE
    NO MAXVALUE
    CACHE 1;

-- Name: audit_events_id_seq; Type: SEQUENCE OWNED BY; Schema: public; Owner: -

ALTER SEQUENCE public.audit_events_id_seq OWNED BY public.audit_events.id;

