    error_message text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT pii_scan_jobs_mode_check CHECK ((mode = ANY (ARRAY['detect'::text, 'block'::text, 'transform'::text]))),
    CONSTRAINT pii_scan_jobs_status_check CHECK ((status = ANY (ARRAY['queued'::text, 'claimed'::text, 'completed'::text, 'failed'::text]))),
    CONSTRAINT pii_scan_jobs_subject_type_check CHECK ((subject_type = ANY (ARRAY['message'::text, 'artifact'::text])))
);

