    CONSTRAINT pii_scan_runs_mode_check CHECK ((mode = ANY (ARRAY['off'::text, 'detect'::text, 'block'::text, 'transform'::text]))),
    CONSTRAINT pii_scan_runs_status_check CHECK ((status = ANY (ARRAY['pending'::text, 'processing'::text, 'completed'::text, 'failed'::text, 'blocked'::text, 'transformed'::text]))),
    CONSTRAINT pii_scan_runs_subject_type_check CHECK ((subject_type = ANY (ARRAY['message'::text, 'artifact'::text])))
);

